/*
Cost model based on symbol statistics.
type: CostModelFun
*/
static double GetCostStat(unsigned litlen, unsigned dist, void *context)
{
    SymbolStats *stats = (SymbolStats *)context;
    if (dist == 0)
    {
        return stats->ll_symbols[litlen];
    }
    else
    {
        int lsym = ZopfliGetLengthSymbol(litlen);
        int lbits = ZopfliGetLengthExtraBits(litlen);
        int dsym = ZopfliGetDistSymbol(dist);
        int dbits = ZopfliGetDistExtraBits(dist);
        return lbits + dbits + stats->ll_symbols[lsym] + stats->d_symbols[dsym];
    }
}

/*
Cost model which should exactly match fixed tree.
type: CostModelFun
*/
static double GetCostFixed(unsigned litlen, unsigned dist, void *unused)
// clang-format off
/* Fixed-tree cost model: the bit length a (litlen, dist) pair occupies in the
   DEFLATE fixed Huffman encoding.  litlen is a literal byte (dist==0) or a
   DEFLATE length (dist!=0), bounded by the 259-entry length tables the callees
   index; dist is a DEFLATE distance, 0 in the literal regime and in [1,32768]
   otherwise. */
__CPROVER_requires(litlen <= 258 && dist <= 32768)
__CPROVER_assigns()
/* Literal regime: fixed-tree literal codes are 8 bits for symbols 0..143 and
   9 bits for 144..255, exactly reproducing the fixed Huffman table.  Pinning
   the value to a single constant on each side of 143 kills every comparison
   mutant on `litlen <= 143`. */
__CPROVER_ensures(dist == 0 ==>
    __CPROVER_return_value == (litlen <= 143 ? 8 : 9))
/* Match regime: the cost is the fixed length-symbol code length (7 bits for
   length symbols 257..279, which are exactly the lengths litlen<=114; 8 bits
   for symbols 280..285, i.e. litlen>=115), plus the constant 5-bit distance
   symbol, plus the length and distance extra bits.  The extra-bit counts are
   reproduced from the same closed forms the callee contracts pin them to
   (ZopfliGetLengthExtraBits / ZopfliGetDistExtraBits), so the result is fixed
   exactly -- killing the `lsym <= 279` comparison mutants via the litlen<=114
   split and the +dbits/+lbits sign mutants via the exact extra-bit terms.  The
   dist==0 -> dist!=0 mutant is killed because it routes the literal case into
   ZopfliGetDistExtraBits(0), violating that callee's requires. */
__CPROVER_ensures(dist != 0 ==>
    __CPROVER_return_value ==
        5 + (litlen <= 114 ? 7 : 8)
        + ((litlen <= 10 || litlen == 258)
               ? 0
               : ((31 ^ __builtin_clz(litlen - 3)) - 2))
        + (dist < 5 ? 0 : ((31 ^ __builtin_clz(dist - 1)) - 1)))
// clang-format on
{
    (void)unused;
    if (dist == 0)
    {
        if (litlen <= 143)
            return 8;
        else
            return 9;
    }
    else
    {
        int dbits = ZopfliGetDistExtraBits(dist);
        int lbits = ZopfliGetLengthExtraBits(litlen);
        int lsym = ZopfliGetLengthSymbol(litlen);
        int cost = 0;
        if (lsym <= 279)
            cost += 7;
        else
            cost += 8;
        cost += 5; /* Every dist symbol has length 5. */
        return cost + dbits + lbits;
    }
}

